import _ from 'lodash';
import type { StatData } from './statSource';

const I = {
  leaf: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" d="M11 20A7 7 0 0 1 9.8 6.1C15.5 5 17 4.48 19 2c1 2 2 4.18 2 8 0 5.5-4.78 10-10 10Z"/><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" d="M2 21c0-3 1.85-5.36 5.08-6C9.5 14.52 12 13 13 12"/></svg>`,
  globe: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="1.75"/><path stroke="currentColor" stroke-width="1.5" d="M3 12h18M12 3a15 15 0 000 18M12 3a15 15 0 010 18"/></svg>`,
  user: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><circle cx="12" cy="8" r="3.5" stroke="currentColor" stroke-width="1.75"/><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" d="M5 20v-1c0-3 2.5-5 7-5s7 2 7 5v1"/></svg>`,
  list: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" d="M8 7h12M8 12h12M8 17h12M4 7h.01M4 12h.01M4 17h.01"/></svg>`,
  backpack: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" d="M9 8V6a3 3 0 016 0v2"/><rect x="5" y="8" width="14" height="12" rx="2" stroke="currentColor" stroke-width="1.75"/><path stroke="currentColor" stroke-width="1.5" d="M9 14h6"/></svg>`,
  target: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><circle cx="12" cy="12" r="8" stroke="currentColor" stroke-width="1.75"/><circle cx="12" cy="12" r="4" stroke="currentColor" stroke-width="1.5"/><circle cx="12" cy="12" r="1.2" fill="currentColor"/></svg>`,
  chat: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" stroke-linejoin="round" d="M5 6h14a2 2 0 012 2v6a2 2 0 01-2 2h-4l-4 3v-3H5a2 2 0 01-2-2V8a2 2 0 012-2z"/></svg>`,
  chart: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" d="M5 19V5M9 19v-6M13 19V9M17 19v-9"/></svg>`,
  spark: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" d="M12 3l1.8 5.2L19 10l-5.2 1.8L12 17l-1.8-5.2L5 10l5.2-1.8L12 3z"/></svg>`,
  grid: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="1.75" d="M5 5h6v6H5V5zm8 0h6v6h-6V5zM5 13h6v6H5v-6zm8 0h6v6h-6v-6z"/></svg>`,
  chevron: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="2" stroke-linecap="round" d="M6 9l6 6 6-6"/></svg>`,
  x: `<svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path stroke="currentColor" stroke-width="2" stroke-linecap="round" d="M6 6l12 12M18 6L6 18"/></svg>`,
};

function rarityClass(r: string): string {
  const k = String(r || 'E').toLowerCase().replace(/\s/g, '');
  if (['e', 'd', 'c', 'b', 'a', 's', 'ss', 'sss', 'ss'].some(x => k === x || k.endsWith(x))) {
    if (k.includes('sss')) return 'rarity-sss';
    if (k === 'ss' || k.startsWith('ss')) return 'rarity-ss';
    return `rarity-${k.slice(0, 1)}`;
  }
  return 'rarity-e';
}

function esc(s: string): string {
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

/** 展示梦魇欲魔「能力列表」全部阶段；当前阶段行高亮 */
function renderNightmareAbilityMatrix(nightmare: Record<string, unknown>): string {
  const abilities = nightmare['能力列表'];
  if (!abilities || typeof abilities !== 'object' || abilities === null || Array.isArray(abilities)) {
    return '<div class="hud-empty hud-empty--inline">暂无能力列表</div>';
  }
  const ab = abilities as Record<string, unknown>;
  const preferred = ['一', '二', '三', '四'];
  const restKeys = Object.keys(ab).filter(k => !preferred.includes(k));
  const keys = [...preferred.filter(k => k in ab), ...restKeys];
  if (!keys.length) {
    return '<div class="hud-empty hud-empty--inline">暂无能力列表</div>';
  }
  const phase = String(nightmare['阶段'] ?? '');
  return keys
    .map(k => {
      const v = ab[k];
      const active = phase === k;
      return `
        <div class="hud-ability-row${active ? ' is-current' : ''}" role="listitem">
          <span class="hud-ability-phase">阶段 ${esc(k)}</span>
          <span class="hud-ability-desc">${esc(v === undefined || v === null ? '——' : String(v))}</span>
        </div>`;
    })
    .join('');
}

function statPairPct(cur: unknown, max: unknown): number {
  const c = Number(cur);
  const m = Number(max);
  if (!Number.isFinite(m) || m <= 0) return 0;
  return _.clamp((Number.isFinite(c) ? c : 0) / m, 0, 1) * 100;
}

export type HudMount = {
  render: (stat: StatData, meta: { sourceMessageId: number | null; usedMock: boolean }) => void;
  destroy: () => void;
};

export function mountHud(container: HTMLElement): HudMount {
  let modalResolveClose: (() => void) | null = null;

  container.innerHTML = `
    <div class="hud-scanline" aria-hidden="true"></div>
    <div class="hud-shell">
      <h1 class="visually-hidden" id="hud-page-title">小岛手册 · 生存状态一览</h1>
      <div class="hud-meta-line">
        <span id="hud-sync-status">同步中…</span>
        <code id="hud-msg-anchor" title="变量锚定的 AI 楼层"></code>
      </div>
      <div class="hud-dock" role="region" aria-label="态势摘要栏">
        <div class="hud-dock__inner">
          <div class="hud-brand">
            <div class="hud-brand__glyph" aria-hidden="true">${I.leaf}</div>
            <div class="hud-brand__text">
              <div class="hud-brand__title">小岛手册</div>
              <div class="hud-brand__sub" id="hud-dock-location">——</div>
            </div>
          </div>
          <div class="hud-dock__stats" id="hud-dock-chips"></div>
          <div class="hud-dock__actions">
            <button type="button" class="hud-btn hud-btn--ghost" id="hud-btn-refresh" title="立即刷新">
              ${I.spark}<span>刷新</span>
            </button>
            <button type="button" class="hud-btn" id="hud-btn-expand" aria-expanded="false" aria-controls="hud-command-panel">
              ${I.grid}<span>指挥面板</span>
            </button>
          </div>
        </div>
      </div>
      <div class="hud-backdrop" id="hud-backdrop" aria-hidden="true"></div>
      <section class="hud-panel" id="hud-command-panel" aria-hidden="true" aria-labelledby="hud-panel-heading">
        <div class="hud-panel__surface">
          <header class="hud-panel__head">
            <div>
              <h2 id="hud-panel-heading">岛屿手册</h2>
              <p>在这里查看世界与角色状态、任务与背包、交易行与论坛等全部叙事变量。</p>
            </div>
            <button type="button" class="hud-btn hud-btn--ghost" id="hud-panel-close" aria-label="关闭面板">${I.x}</button>
          </header>
          <nav class="hud-tabs" role="tablist" aria-label="面板分区" id="hud-tablist"></nav>
          <div class="hud-panel__body" id="hud-tab-panels"></div>
        </div>
      </section>
    </div>
    <div class="hud-modal" id="hud-modal-root" aria-hidden="true" role="dialog" aria-modal="true">
      <div class="hud-modal__backdrop" id="hud-modal-backdrop"></div>
      <div class="hud-modal__card" id="hud-modal-card"></div>
    </div>
  `;

  const el = {
    syncStatus: container.querySelector('#hud-sync-status') as HTMLElement,
    msgAnchor: container.querySelector('#hud-msg-anchor') as HTMLElement,
    dockLocation: container.querySelector('#hud-dock-location') as HTMLElement,
    dockChips: container.querySelector('#hud-dock-chips') as HTMLElement,
    btnRefresh: container.querySelector('#hud-btn-refresh') as HTMLButtonElement,
    btnExpand: container.querySelector('#hud-btn-expand') as HTMLButtonElement,
    backdrop: container.querySelector('#hud-backdrop') as HTMLElement,
    panel: container.querySelector('#hud-command-panel') as HTMLElement,
    btnClose: container.querySelector('#hud-panel-close') as HTMLButtonElement,
    tablist: container.querySelector('#hud-tablist') as HTMLElement,
    tabPanels: container.querySelector('#hud-tab-panels') as HTMLElement,
    modalRoot: container.querySelector('#hud-modal-root') as HTMLElement,
    modalBackdrop: container.querySelector('#hud-modal-backdrop') as HTMLElement,
    modalCard: container.querySelector('#hud-modal-card') as HTMLElement,
  };

  const tabs: { id: string; label: string; icon: string }[] = [
    { id: 'tab-world-hero', label: '世界与主角', icon: I.globe },
    { id: 'tab-quests', label: '任务与行动', icon: I.list },
    { id: 'tab-gear', label: '物资与背包', icon: I.backpack },
    { id: 'tab-hunt', label: '狩猎名单', icon: I.target },
    { id: 'tab-market', label: '交易与副本', icon: I.chart },
    { id: 'tab-social', label: '论坛与排行', icon: I.chat },
    { id: 'tab-full', label: '完整变量表', icon: I.grid },
  ];

  function openModal(title: string, innerHtml: string) {
    el.modalCard.innerHTML = `
      <button type="button" class="hud-modal__close" id="hud-modal-x" aria-label="关闭">${I.x}</button>
      <h3>${esc(title)}</h3>
      <div class="hud-modal-body">${innerHtml}</div>
    `;
    el.modalRoot.classList.add('is-open');
    el.modalRoot.setAttribute('aria-hidden', 'false');
    const close = () => {
      el.modalRoot.classList.remove('is-open');
      el.modalRoot.setAttribute('aria-hidden', 'true');
      el.modalCard.innerHTML = '';
      modalResolveClose = null;
    };
    modalResolveClose = close;
    el.modalCard.querySelector('#hud-modal-x')?.addEventListener('click', close);
  }

  el.modalBackdrop.addEventListener('click', () => modalResolveClose?.());

  function setPanelOpen(open: boolean) {
    el.backdrop.classList.toggle('is-open', open);
    el.panel.classList.toggle('is-open', open);
    el.panel.setAttribute('aria-hidden', open ? 'false' : 'true');
    el.btnExpand.setAttribute('aria-expanded', open ? 'true' : 'false');
  }

  function bindTabNavigation() {
    el.tablist.querySelectorAll<HTMLButtonElement>('.hud-tab').forEach(btn => {
      btn.addEventListener('click', () => {
        const id = btn.dataset.tabTarget;
        el.tablist.querySelectorAll('.hud-tab').forEach(b => b.classList.remove('is-active'));
        btn.classList.add('is-active');
        el.tabPanels.querySelectorAll<HTMLElement>('.hud-tab-panel').forEach(p => {
          p.hidden = p.id !== id;
        });
      });
    });
  }

  function buildTabs(stat: StatData) {
    el.tablist.innerHTML = tabs
      .map(
        (t, i) => `
      <button type="button" class="hud-tab ${i === 0 ? 'is-active' : ''}" role="tab" id="${t.id}-btn" data-tab-target="${t.id}" aria-selected="${i === 0}">
        ${t.icon}<span>${esc(t.label)}</span>
      </button>`,
      )
      .join('');

    el.tabPanels.innerHTML = `
      <div class="hud-tab-panel" id="tab-world-hero" role="tabpanel">
        ${renderWorldHero(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-quests" role="tabpanel" hidden>
        ${renderQuestsActions(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-gear" role="tabpanel" hidden>
        ${renderGear(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-hunt" role="tabpanel" hidden>
        ${renderHunt(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-market" role="tabpanel" hidden>
        ${renderMarketDungeon(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-social" role="tabpanel" hidden>
        ${renderForumRank(stat)}
      </div>
      <div class="hud-tab-panel" id="tab-full" role="tabpanel" hidden>
        ${renderFullTree(stat)}
      </div>
    `;

    el.tabPanels.querySelectorAll<HTMLElement>('.hud-tab-panel').forEach((p, i) => {
      p.hidden = i !== 0;
    });

    bindTabNavigation();
    wireItemCards(stat);
    wireDungeonCards(stat);
    wireShopRows(stat);
  }

  function wireShopRows(stat: StatData) {
    const trade = _.get(stat, '交易行') as
      | {
          系统商城?: Record<string, Record<string, unknown>>;
          玩家交易?: Record<string, Record<string, unknown>>;
        }
      | undefined;

    el.tabPanels.querySelectorAll<HTMLButtonElement>('[data-sys-shop-key]').forEach(btn => {
      btn.addEventListener('click', () => {
        const key = btn.dataset.sysShopKey!;
        const row = trade?.['系统商城']?.[key];
        if (!row) return;
        openModal(
          String(row['名称'] ?? '货架条目'),
          `
          <div class="hud-grid" style="margin-top:8px">
            ${kv('货架键', key)}
            ${kv('名称', row['名称'])}
            ${kv('价格', row['价格'] !== undefined && row['价格'] !== null ? `${row['价格']} SP` : '——')}
            ${kv('备注', row['备注'])}
          </div>
        `,
        );
      });
    });

    el.tabPanels.querySelectorAll<HTMLButtonElement>('[data-ply-trade-key]').forEach(btn => {
      btn.addEventListener('click', () => {
        const key = btn.dataset.plyTradeKey!;
        const row = trade?.['玩家交易']?.[key];
        if (!row) return;
        openModal(
          String(row['物品名称'] ?? '玩家挂单'),
          `
          <div class="hud-grid" style="margin-top:8px">
            ${kv('挂单键', key)}
            ${kv('物品名称', row['物品名称'])}
            ${kv('售卖人', row['售卖人'])}
            ${kv('上架时间', row['上架时间'])}
            ${kv('价格', row['价格'] !== undefined && row['价格'] !== null ? `${row['价格']} SP` : '——')}
          </div>
        `,
        );
      });
    });
  }

  function wireItemCards(stat: StatData) {
    el.tabPanels.querySelectorAll<HTMLButtonElement>('[data-item-key]').forEach(btn => {
      btn.addEventListener('click', () => {
        const key = btn.dataset.itemKey!;
        const items = _.get(stat, '物品栏') as Record<string, Record<string, unknown>> | undefined;
        const item = items?.[key];
        if (!item) return;
        openModal(
          String(item['名称'] ?? '物品'),
          `
          <div class="hud-grid" style="margin-top:8px">
            ${kv('内部键', key)}
            ${kv('名称', item['名称'])}
            ${kv('数量', item['数量'])}
            ${kv('最大堆叠', item['最大堆叠'])}
            ${kv('稀有度', item['稀有度'])}
          </div>
          <p style="margin-top:14px;font-size:13px;line-height:1.6;color:var(--muted)">${esc(String(item['描述'] ?? ''))}</p>
        `,
        );
      });
    });
  }

  function wireDungeonCards(stat: StatData) {
    el.tabPanels.querySelectorAll<HTMLButtonElement>('[data-dungeon-key]').forEach(btn => {
      btn.addEventListener('click', () => {
        const key = btn.dataset.dungeonKey!;
        const dungeons = _.get(stat, '副本列表') as Record<string, Record<string, unknown>> | undefined;
        const d = dungeons?.[key];
        if (!d) return;
        openModal(
          String(d['副本名称'] ?? '副本'),
          `
          <div class="hud-grid" style="margin-top:8px">
            ${kv('标识', key)}
            ${kv('难度', d['副本难度'])}
            ${kv('地点', d['副本地点'])}
            ${kv('奖励', d['副本奖励'])}
          </div>
          <p style="margin-top:14px;font-size:13px;line-height:1.55;color:var(--muted)">${esc(String(d['副本内容'] ?? ''))}</p>
        `,
        );
      });
    });
  }

  function kv(k: string, v: unknown) {
    return `<div class="hud-kv"><div class="hud-kv__k">${esc(k)}</div><div class="hud-kv__v">${esc(v === undefined || v === null ? '——' : String(v))}</div></div>`;
  }

  function renderWorldHero(stat: StatData) {
    const w = _.get(stat, '世界') as Record<string, unknown> | undefined;
    const h = _.get(stat, '主角') as Record<string, unknown> | undefined;
    const nightmare = (h?.['梦魇欲魔'] as Record<string, unknown>) || {};

    const worldGrid =
      w &&
      Object.entries(w)
        .map(([k, v]) => kv(k, v))
        .join('');

    const strPct = statPairPct(_.get(h, '力量.当前'), _.get(h, '力量.上限'));
    const conPct = statPairPct(_.get(h, '体质.当前'), _.get(h, '体质.上限'));
    const dexPct = statPairPct(_.get(h, '敏捷.当前'), _.get(h, '敏捷.上限'));

    const hunger = Number(_.get(h, '饱食度'));
    const pollution = Number(_.get(h, '污染值'));

    return `
      <section class="hud-section" aria-labelledby="sec-world">
        <h3 class="hud-section__title" id="sec-world">${I.globe}世界态势</h3>
        <div class="hud-grid">${worldGrid || '<div class="hud-empty">暂无世界字段</div>'}</div>
      </section>
      <section class="hud-section" aria-labelledby="sec-hero">
        <h3 class="hud-section__title" id="sec-hero">${I.user}主角档案</h3>
        <div class="hud-hero-card">
          <div class="hud-hero-top">
            <div>
              <p class="hud-hero-name">${esc(String(h?.['姓名'] ?? '未知'))}</p>
              <p style="margin:6px 0 0;font-size:12px;color:var(--muted)">
                ${esc(String(h?.['昵称'] ?? ''))} · UID ${esc(String(h?.['uid'] ?? ''))}
                ${h?.['种族'] ? ` · ${esc(String(h['种族']))}` : ''}
              </p>
            </div>
            <span class="hud-badge-rank">总评 ${esc(String(h?.['角色总评'] ?? '—'))}</span>
          </div>
          ${
            h?.['角色总评评语']
              ? `<p style="margin-top:8px;font-size:11px;color:var(--muted);line-height:1.45">${esc(String(h['角色总评评语']))}</p>`
              : ''
          }
          <div class="hud-nightmare" aria-labelledby="nightmare-heading">
            <div class="hud-nightmare__head">
              <span id="nightmare-heading" class="hud-nightmare__title">梦魇欲魔谱系</span>
              <span class="hud-nightmare__badge">${esc(String(nightmare['名称'] ?? '梦魇欲魔'))}</span>
            </div>
            <p class="hud-nightmare__current">当前阶段 <strong>${esc(String(nightmare['阶段'] ?? '——'))}</strong></p>
            <div class="hud-ability-matrix" role="list" aria-label="各阶段能力">${renderNightmareAbilityMatrix(nightmare)}</div>
          </div>
          <div class="hud-grid" style="grid-template-columns:repeat(auto-fill,minmax(120px,1fr));position:relative;z-index:1">
            ${kv('SP', h?.['sp'])}
            ${kv('污染值', h?.['污染值'])}
            ${kv('饱食度', h?.['饱食度'])}
          </div>
          <div class="hud-stat-row">
            <div class="hud-stat-block">
              <div class="hud-stat-block__label">力量 ${_.get(h, '力量.当前')}/${_.get(h, '力量.上限')}</div>
              <div class="hud-meter"><div class="hud-meter__fill hud-meter__fill--ember" style="width:${strPct}%"></div></div>
            </div>
            <div class="hud-stat-block">
              <div class="hud-stat-block__label">体质 ${_.get(h, '体质.当前')}/${_.get(h, '体质.上限')}</div>
              <div class="hud-meter"><div class="hud-meter__fill" style="width:${conPct}%"></div></div>
            </div>
            <div class="hud-stat-block">
              <div class="hud-stat-block__label">敏捷 ${_.get(h, '敏捷.当前')}/${_.get(h, '敏捷.上限')}</div>
              <div class="hud-meter"><div class="hud-meter__fill" style="width:${dexPct}%;background:linear-gradient(90deg,var(--violet),var(--cyan))"></div></div>
            </div>
          </div>
          <div style="display:flex;gap:10px;flex-wrap:wrap;position:relative;z-index:1;margin-top:4px">
            <span class="hud-chip hud-chip--ember">饱食 <strong>${Number.isFinite(hunger) ? hunger : '—'}</strong></span>
            <span class="hud-chip hud-chip--cyan">污染 <strong>${Number.isFinite(pollution) ? pollution : '—'}</strong></span>
          </div>
        </div>
      </section>
    `;
  }

  function renderQuestsActions(stat: StatData) {
    const tasks = _.get(stat, '任务列表') as Record<string, Record<string, unknown>> | undefined;
    const next = _.get(stat, '下一步行动') as Record<string, string> | undefined;

    const taskCards =
      tasks &&
      Object.entries(tasks)
        .map(([id, t]) => {
          const prog = Number(t['进度']);
          const pct = Number.isFinite(prog) ? _.clamp(prog, 0, 100) : 0;
          return `
        <article class="hud-task-card" data-task-id="${esc(id)}">
          <h3>${esc(String(t['标题'] ?? id))}</h3>
          <p>${esc(String(t['描述'] ?? ''))}</p>
          <div style="display:flex;justify-content:space-between;align-items:center;font-size:11px;color:var(--muted);margin-bottom:6px">
            <span>奖励：${esc(String(t['奖励'] ?? ''))}</span>
            <span>${pct}%</span>
          </div>
          <div class="hud-progress"><div class="hud-progress__fill" style="width:${pct}%"></div></div>
        </article>`;
        })
        .join('');

    const actions =
      next &&
      (['选项A', '选项B', '选项C', '选项D'] as const)
        .map(k => {
          const label = next[k];
          if (!label) return '';
          return `
        <button type="button" class="hud-action-btn" data-action="${esc(k)}">
          <span>${esc(k)}</span>
          ${esc(label)}
        </button>`;
        })
        .join('');

    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.list}任务列表</h3>
        ${taskCards || '<div class="hud-empty">暂无任务条目</div>'}
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">${I.spark}下一步行动</h3>
        <div class="hud-action-grid">${actions || '<div class="hud-empty">暂无行动选项</div>'}</div>
      </section>
    `;
  }

  function renderGear(stat: StatData) {
    const bag = _.get(stat, '背包') as Record<string, unknown> | undefined;
    const items = _.get(stat, '物品栏') as Record<string, Record<string, unknown>> | undefined;
    const used = Number(bag?.['已用格子']);
    const cap = Number(bag?.['格子上限']);
    const pct = Number.isFinite(used) && Number.isFinite(cap) && cap > 0 ? _.clamp((used / cap) * 100, 0, 100) : 0;

    const itemCards =
      items &&
      Object.entries(items)
        .map(([key, it]) => {
          const r = String(it['稀有度'] ?? 'E');
          return `
      <button type="button" class="hud-item-card" data-item-key="${esc(key)}">
        <div class="hud-item-card__top">
          <h4 class="hud-item-card__name">${esc(String(it['名称'] ?? key))}</h4>
          <span class="hud-rarity ${rarityClass(r)}">${esc(r)}</span>
        </div>
        <div style="font-size:11px;color:var(--muted)">× ${esc(String(it['数量'] ?? ''))} / 堆叠上限 ${esc(String(it['最大堆叠'] ?? ''))}</div>
        <p style="margin:8px 0 0;font-size:12px;line-height:1.45;color:var(--muted)">${esc(String(it['描述'] ?? '').slice(0, 80))}${String(it['描述'] ?? '').length > 80 ? '…' : ''}</p>
      </button>`;
        })
        .join('');

    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.backpack}背包占用</h3>
        <div class="hud-kv" style="max-width:420px">
          <div class="hud-kv__k">格子</div>
          <div class="hud-kv__v">${esc(String(bag?.['已用格子'] ?? '—'))} / ${esc(String(bag?.['格子上限'] ?? '—'))}</div>
          <div class="hud-mini-meter" style="margin-top:10px;width:100%"><div class="hud-mini-meter__fill hud-mini-meter__fill--cyan" style="width:${pct}%"></div></div>
        </div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">物品栏</h3>
        <div class="hud-item-grid">${itemCards || '<div class="hud-empty">暂无物品</div>'}</div>
      </section>
    `;
  }

  function renderHuntSection(title: string, block: Record<string, Record<string, unknown>> | undefined) {
    if (!block || !Object.keys(block).length) {
      return `<div class="hud-empty">${title}暂无条目</div>`;
    }
    return Object.entries(block)
      .map(([key, row]) => {
        const keys = Object.keys(row);
        const dls = keys
          .map(k => {
            const v = row[k];
            const text =
              v !== null && typeof v === 'object' ? JSON.stringify(v) : v === undefined ? '' : String(v);
            return `<dt>${esc(k)}</dt><dd>${esc(text)}</dd>`;
          })
          .join('');
        return `
      <article class="hud-hunt-card" data-hunt-key="${esc(key)}">
        <h4>${esc(key)}</h4>
        <dl>${dls}</dl>
      </article>`;
      })
      .join('');
  }

  function renderHunt(stat: StatData) {
    const hunt = _.get(stat, '狩猎名单') as
      | {
          进行中?: Record<string, Record<string, unknown>>;
          已奴隶?: Record<string, Record<string, unknown>>;
        }
      | undefined;

    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.target}进行中</h3>
        <div class="hud-hunt-grid" style="grid-template-columns:1fr">
        ${renderHuntSection('进行中', hunt?.['进行中'])}
        </div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">已收容</h3>
        <div class="hud-hunt-grid" style="grid-template-columns:1fr">${renderHuntSection('已奴隶', hunt?.['已奴隶'])}</div>
      </section>
    `;
  }

  function renderMarketDungeon(stat: StatData) {
    const trade = _.get(stat, '交易行') as
      | {
          系统商城?: Record<string, Record<string, unknown>>;
          玩家交易?: Record<string, Record<string, unknown>>;
        }
      | undefined;

    const sysRows =
      trade?.['系统商城'] &&
      Object.entries(trade['系统商城'])
        .map(([id, row]) => {
          return `
        <button type="button" class="hud-shop-row hud-shop-row--btn" data-sys-shop-key="${esc(id)}">
          <div class="hud-shop-row__main">
            <div style="font-weight:700">${esc(String(row['名称'] ?? id))}</div>
            <div style="font-size:11px;color:var(--muted);margin-top:4px">${esc(String(row['备注'] ?? ''))}</div>
          </div>
          <div style="font-weight:800;color:var(--ember)">${esc(String(row['价格'] ?? ''))} SP</div>
        </button>`;
        })
        .join('');

    const plyRows =
      trade?.['玩家交易'] &&
      Object.entries(trade['玩家交易'])
        .map(([id, row]) => {
          return `
        <button type="button" class="hud-shop-row hud-shop-row--btn" data-ply-trade-key="${esc(id)}">
          <div class="hud-shop-row__main">
            <div style="font-weight:700">${esc(String(row['物品名称'] ?? id))}</div>
            <div style="font-size:11px;color:var(--muted);margin-top:4px">${esc(String(row['售卖人'] ?? ''))} · ${esc(String(row['上架时间'] ?? ''))}</div>
          </div>
          <div style="font-weight:800;color:var(--cyan)">${esc(String(row['价格'] ?? ''))} SP</div>
        </button>`;
        })
        .join('');

    const dungeons = _.get(stat, '副本列表') as Record<string, Record<string, unknown>> | undefined;
    const dCards =
      dungeons &&
      Object.entries(dungeons)
        .map(([key, d]) => {
          return `
      <button type="button" class="hud-dungeon-card" data-dungeon-key="${esc(key)}" style="cursor:pointer;width:100%;text-align:left;font:inherit;color:inherit">
        <h3>${esc(String(d['副本名称'] ?? key))}</h3>
        <p>${esc(String(d['副本内容'] ?? ''))}</p>
        <div class="hud-dungeon-meta">
          <span class="hud-tag">难度 ${esc(String(d['副本难度'] ?? ''))}</span>
          <span class="hud-tag">${esc(String(d['副本地点'] ?? ''))}</span>
          <span class="hud-tag">奖励 ${esc(String(d['副本奖励'] ?? ''))}</span>
        </div>
      </button>`;
        })
        .join('');

    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.chart}交易行</h3>
        <div class="hud-trade-split">
          <div>
            <div class="hud-section__title" style="margin-bottom:8px;font-size:11px">系统商城</div>
            ${sysRows || '<div class="hud-empty">暂无货架</div>'}
          </div>
          <div>
            <div class="hud-section__title" style="margin-bottom:8px;font-size:11px">玩家交易</div>
            ${plyRows || '<div class="hud-empty">暂无挂单</div>'}
          </div>
        </div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">副本列表</h3>
        ${dCards || '<div class="hud-empty">暂无副本</div>'}
      </section>
    `;
  }

  function renderForumRank(stat: StatData) {
    const forum = _.get(stat, '玩家论坛') as
      | {
          帖子?: Record<string, Record<string, unknown>>;
          私信?: Record<string, Record<string, unknown>>;
        }
      | undefined;

    const posts =
      forum?.['帖子'] &&
      Object.entries(forum['帖子'])
        .map(([_, p]) => {
          return `
      <article class="hud-forum-post">
        <div class="hud-forum-post__meta"><span>${esc(String(p['发帖人'] ?? ''))}</span><span>${esc(String(p['发帖时间'] ?? ''))}</span></div>
        <p>${esc(String(p['内容'] ?? ''))}</p>
      </article>`;
        })
        .join('');

    const dms =
      forum?.['私信'] &&
      Object.entries(forum['私信'])
        .map(([_, p]) => {
          return `
      <article class="hud-forum-post">
        <div class="hud-forum-post__meta"><span>${esc(String(p['发送人'] ?? ''))}</span><span>${esc(String(p['发送时间'] ?? ''))}</span></div>
        <p>${esc(String(p['内容'] ?? ''))}</p>
      </article>`;
        })
        .join('');

    const ranks = _.get(stat, '排行榜') as Record<string, Record<string, unknown>> | undefined;
    const rankRows =
      ranks &&
      Object.entries(ranks)
        .sort((a, b) => Number(a[1]['排名']) - Number(b[1]['排名']))
        .map(([_, r]) => {
          const n = Number(r['排名']);
          const cls = n === 1 ? 'hud-rank-num hud-rank-num--1' : 'hud-rank-num';
          return `
      <div class="hud-rank-row">
        <div class="${cls}">${esc(String(r['排名'] ?? ''))}</div>
        <div style="font-weight:700">${esc(String(r['上榜人昵称'] ?? ''))}</div>
      </div>`;
        })
        .join('');

    const dialogs = _.get(stat, '界面对话') as Array<{ 角色?: string; 文本?: string }> | undefined;
    const bubbles =
      dialogs &&
      dialogs
        .map(line => {
          const isAi = line['角色'] === 'ai';
          return `
      <div class="hud-bubble ${isAi ? 'hud-bubble--ai' : 'hud-bubble--player'}">${esc(String(line['文本'] ?? ''))}</div>`;
        })
        .join('');

    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.chat}玩家论坛 · 帖子</h3>
        <div class="hud-forum-list">${posts || '<div class="hud-empty">暂无帖子</div>'}</div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">私信</h3>
        <div class="hud-forum-list">${dms || '<div class="hud-empty">暂无私信</div>'}</div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">${I.chart}排行榜</h3>
        <div class="hud-rank-list">${rankRows || '<div class="hud-empty">暂无排行</div>'}</div>
      </section>
      <section class="hud-section">
        <h3 class="hud-section__title">界面对话流</h3>
        <div class="hud-dialog-stream">${bubbles || '<div class="hud-empty">暂无对话</div>'}</div>
      </section>
    `;
  }

  function renderFullTree(stat: StatData) {
    const json = JSON.stringify(stat, null, 2);
    return `
      <section class="hud-section">
        <h3 class="hud-section__title">${I.grid}stat_data 完整导出</h3>
        <p style="font-size:12px;color:var(--muted);margin:0 0 12px;line-height:1.55">
          以下为当前锚定楼层解析到的完整 <code>stat_data</code> 对象（含全部键）。若叙事扩展了新字段，将自动出现在此树中。
        </p>
        <pre class="hud-tree" id="hud-full-json" aria-label="完整变量 JSON">${esc(json)}</pre>
      </section>
    `;
  }

  function updateDock(stat: StatData, meta: { sourceMessageId: number | null; usedMock: boolean }) {
    const w = _.get(stat, '世界') as Record<string, unknown> | undefined;
    const h = _.get(stat, '主角') as Record<string, unknown> | undefined;

    el.dockLocation.textContent = `${String(w?.['日期'] ?? '')} · ${String(w?.['地点'] ?? '').slice(0, 36)}${String(w?.['地点'] ?? '').length > 36 ? '…' : ''}`;

    const hunger = Number(h?.['饱食度']);
    const poll = Number(h?.['污染值']);
    const hpct = Number.isFinite(hunger) ? _.clamp(hunger, 0, 100) : 0;
    const ppct = Number.isFinite(poll) ? _.clamp(poll, 0, 100) : 0;

    el.dockChips.innerHTML = `
      <span class="hud-chip hud-chip--ember">SP <strong>${esc(String(h?.['sp'] ?? '—'))}</strong></span>
      <span class="hud-chip">天数 <strong>${esc(String(w?.['生存天数'] ?? '—'))}</strong></span>
      <span class="hud-chip hud-chip--cyan">饱食
        <span class="hud-mini-meter" aria-hidden="true"><span class="hud-mini-meter__fill hud-mini-meter__fill--toxic" style="width:${hpct}%"></span></span>
        <strong>${Number.isFinite(hunger) ? hunger : '—'}</strong>
      </span>
      <span class="hud-chip">污染
        <span class="hud-mini-meter" aria-hidden="true"><span class="hud-mini-meter__fill" style="width:${ppct}%"></span></span>
        <strong>${Number.isFinite(poll) ? poll : '—'}</strong>
      </span>
    `;

    el.syncStatus.textContent = meta.usedMock ? '演示数据（未读到楼层变量）' : '已同步最新 AI 楼层变量';
    el.msgAnchor.textContent =
      meta.sourceMessageId !== null ? `锚定楼层 #${meta.sourceMessageId}` : '无可用 AI 楼层';
  }

  const onExpand = () => {
    const open = !el.panel.classList.contains('is-open');
    setPanelOpen(open);
  };

  el.btnExpand.addEventListener('click', onExpand);
  el.btnClose.addEventListener('click', () => setPanelOpen(false));
  el.backdrop.addEventListener('click', () => setPanelOpen(false));

  function render(stat: StatData, meta: { sourceMessageId: number | null; usedMock: boolean }) {
    updateDock(stat, meta);
    buildTabs(stat);
  }

  return {
    render,
    destroy: () => {
      el.btnExpand.removeEventListener('click', onExpand);
      container.innerHTML = '';
    },
  };
}
