import './hud.css';
import $ from 'jquery';
import _ from 'lodash';
import { fetchLatestStatData } from './statSource';
import { mountHud } from './domHud';

function applyMeta() {
  document.title = '小岛手册 · 生存状态一览';
  let metaDesc = document.querySelector('meta[name="description"]');
  if (!metaDesc) {
    metaDesc = document.createElement('meta');
    metaDesc.setAttribute('name', 'description');
    document.head.appendChild(metaDesc);
  }
  metaDesc.setAttribute(
    'content',
    '动物森友会式柔和界面：自动锚定最新 AI 楼层，解析 MVU stat_data，展示世界、主角、任务、背包、狩猎、交易、副本、论坛、排行与界面对话。',
  );
}

function init() {
  applyMeta();
  const root = document.getElementById('app');
  if (!root) {
    console.error('[沉浸状态栏] 缺少挂载节点 #app');
    return;
  }

  let lastSnap = '';
  const hud = mountHud(root);

  const pull = () => {
    try {
      const { stat, sourceMessageId, usedMock } = fetchLatestStatData();
      const snap = JSON.stringify(stat);
      if (snap === lastSnap && lastSnap !== '') {
        return;
      }
      lastSnap = snap;
      hud.render(stat, { sourceMessageId, usedMock });
    } catch (e) {
      console.warn('[沉浸状态栏] 变量读取失败', e);
    }
  };

  pull();
  console.info('[沉浸状态栏] 已挂载小岛手册 HUD');

  $('#hud-btn-refresh').on('click.refreshHud', pull);

  $(document).on('keydown.hudEsc', e => {
    if (e.key !== 'Escape') {
      return;
    }
    $('#hud-backdrop').removeClass('is-open');
    $('#hud-command-panel').removeClass('is-open').attr('aria-hidden', 'true');
    $('#hud-btn-expand').attr('aria-expanded', 'false');
    $('#hud-modal-root').removeClass('is-open').attr('aria-hidden', 'true');
    $('#hud-modal-card').empty();
  });

  const debounced = _.debounce(pull, 140);
  const e1 = eventOn(tavern_events.MESSAGE_UPDATED, debounced);
  const e2 = eventOn(tavern_events.GENERATION_ENDED, debounced);
  const e3 = eventOn(tavern_events.CHAT_CHANGED, () => {
    lastSnap = '';
    debounced();
  });

  const timer = window.setInterval(pull, 2600);

  $(window).on('pagehide.hud', () => {
    window.clearInterval(timer);
    $(document).off('keydown.hudEsc');
    $('#hud-btn-refresh').off('.refreshHud');
    e1.stop();
    e2.stop();
    e3.stop();
    hud.destroy();
  });
}

$(() => {
  errorCatched(init)();
});
