import _ from 'lodash';
import { MOCK_STAT_DATA } from './mockData';

export type StatData = Record<string, unknown>;

/**
 * 锚定「当前聊天记录中最后一条 AI（assistant）消息」的楼层号。
 * 使用 getLastMessageId 确定范围上界，再按 role 筛选，取时间上最后一条 assistant。
 */
function findLastAssistantMessageId(): number | null {
  const lastId = getLastMessageId();
  if (lastId < 0) {
    return null;
  }
  const assistants = getChatMessages(`0-${lastId}`, { role: 'assistant' });
  if (!assistants.length) {
    return null;
  }
  return assistants[assistants.length - 1].message_id;
}

function readRawForMessage(messageId: number): Record<string, unknown> | null {
  try {
    if (typeof window !== 'undefined' && typeof Mvu !== 'undefined' && Mvu?.getMvuData) {
      return Mvu.getMvuData({ type: 'message', message_id: messageId }) as unknown as Record<string, unknown>;
    }
    return getVariables({ type: 'message', message_id: messageId }) as Record<string, unknown>;
  } catch {
    return null;
  }
}

export function fetchLatestStatData(): { stat: StatData; sourceMessageId: number | null; usedMock: boolean } {
  const targetMsgId = findLastAssistantMessageId();
  if (targetMsgId === null) {
    return { stat: _.cloneDeep(MOCK_STAT_DATA), sourceMessageId: null, usedMock: true };
  }
  const raw = readRawForMessage(targetMsgId);
  const stat = _.get(raw, 'stat_data') as StatData | undefined;
  if (stat && typeof stat === 'object' && !Array.isArray(stat) && Object.keys(stat).length > 0) {
    return { stat, sourceMessageId: targetMsgId, usedMock: false };
  }
  return { stat: _.cloneDeep(MOCK_STAT_DATA), sourceMessageId: targetMsgId, usedMock: true };
}
